import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';
import { apiClient } from '../utils/apiClient';

const OWNER_CAPABILITIES = [
  {
    key: 'listings',
    title: 'Manage Workspace Listings',
    description: 'Create, update, and publish workspace inventory with pricing, capacity, and availability controls.',
    icon: '🏢',
    actionType: 'tab',
    tab: 'spaces',
    actionLabel: 'Go to Listings'
  },
  {
    key: 'amenities',
    title: 'Manage Amenities',
    description: 'Highlight amenities and services for each workspace to improve visibility and conversions.',
    icon: '🛠️',
    actionType: 'tab',
    tab: 'spaces',
    actionLabel: 'Edit Amenities'
  },
  {
    key: 'bookings',
    title: 'Manage Bookings',
    description: 'Track every reservation, confirm requests, and monitor payment states in one place.',
    icon: '📅',
    actionType: 'tab',
    tab: 'bookings',
    actionLabel: 'View Bookings'
  },
  {
    key: 'agreements',
    title: 'Manage Agreements/Documents',
    description: 'Keep track of signed agreements and supporting documents tied to each booking.',
    icon: '📄',
    actionType: 'info',
    badge: 'Workflow'
  },
  {
    key: 'images',
    title: 'Manage Workspace Images',
    description: 'Upload high-impact visuals to showcase every workspace experience.',
    icon: '🖼️',
    actionType: 'tab',
    tab: 'spaces',
    actionLabel: 'Update Gallery'
  },
  {
    key: 'reviews',
    title: 'Manage Reviews',
    description: 'Monitor guest feedback and respond to reviews to build trust with future guests.',
    icon: '⭐',
    actionType: 'info',
    badge: 'Engagement'
  },
  {
    key: 'reports',
    title: 'View Earnings & Reports',
    description: 'Get real-time insights into revenue, occupancy, and tour interest.',
    icon: '📈',
    actionType: 'tab',
    tab: 'stats',
    actionLabel: 'Open Reports'
  },
  {
    key: 'history',
    title: 'View Booking History',
    description: 'Access historical bookings for audits, reconciliations, and trend analysis.',
    icon: '🗂️',
    actionType: 'tab',
    tab: 'bookings',
    actionLabel: 'See History'
  },
  {
    key: 'profile',
    title: 'Update Profile',
    description: 'Keep contact information and workspace owner profile details up to date.',
    icon: '🧑‍💼',
    actionType: 'link',
    href: '/profile',
    actionLabel: 'Edit Profile'
  },
  {
    key: 'support',
    title: 'Contact Support',
    description: 'Reach our concierge team for onboarding, payouts, and operational questions.',
    icon: '💬',
    actionType: 'link',
    href: '/contact',
    actionLabel: 'Contact Support'
  }
];

export default function WorkspaceOwnerDashboard() {
  const [activeTab, setActiveTab] = useState('spaces');
  const [spaces, setSpaces] = useState([]);
  const [bookings, setBookings] = useState([]);
  const [tourBookings, setTourBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [stats, setStats] = useState({
    totalSpaces: 0,
    totalBookings: 0,
    activeBookings: 0,
    totalRevenue: 0
  });
  const handleCapabilitySelect = (capability) => {
    if (capability.actionType === 'tab' && capability.tab) {
      setActiveTab(capability.tab);
      const tabSection = document.getElementById('owner-tabs');
      if (tabSection) {
        tabSection.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    }
  };

  useEffect(() => {
    loadStats();
  }, []);

  useEffect(() => {
    if (activeTab === 'spaces') loadSpaces();
    if (activeTab === 'bookings') loadBookings();
    if (activeTab === 'tours') loadTourBookings();
  }, [activeTab]);

  const loadStats = async () => {
    try {
      setLoading(true);
      // Load spaces to calculate stats
      const spacesData = await apiClient.get('/spaces');
      const spacesList = spacesData.data || [];
      
      // Load bookings (you might need to filter by workspace owner)
      const bookingsData = await apiClient.get('/bookings');
      const bookingsList = bookingsData.bookings || [];
      
      const activeBookings = bookingsList.filter(b => 
        b.status === 'confirmed' || b.status === 'pending'
      ).length;
      
      const totalRevenue = bookingsList
        .filter(b => b.paymentStatus === 'paid')
        .reduce((sum, b) => sum + (b.totalAmount || 0), 0);
      
      setStats({
        totalSpaces: spacesList.length,
        totalBookings: bookingsList.length,
        activeBookings,
        totalRevenue
      });
    } catch (err) {
      setError(err.message || 'Failed to load statistics');
    } finally {
      setLoading(false);
    }
  };

  const loadSpaces = async () => {
    try {
      const data = await apiClient.get('/spaces');
      setSpaces(data.data || []);
    } catch (err) {
      setError(err.message || 'Failed to load spaces');
    }
  };

  const loadBookings = async () => {
    try {
      const data = await apiClient.get('/bookings');
      setBookings(data.bookings || []);
    } catch (err) {
      setError(err.message || 'Failed to load bookings');
    }
  };

  const loadTourBookings = async () => {
    try {
      const data = await apiClient.get('/bookings/tours');
      setTourBookings(data.tourBookings || []);
    } catch (err) {
      setError(err.message || 'Failed to load tour bookings');
    }
  };

  const handleDeleteSpace = async (spaceId) => {
    if (!window.confirm('Are you sure you want to delete this space?')) return;
    try {
      await apiClient.delete(`/spaces/${spaceId}`);
      await loadSpaces();
      await loadStats();
    } catch (err) {
      alert(err.message || 'Failed to delete space');
    }
  };

  if (loading && activeTab === 'stats') {
    return (
      <div className="min-h-screen flex flex-col bg-white">
        <Navbar />
        <main className="flex-1 flex items-center justify-center">
          <div className="text-center">
            <svg className="animate-spin h-12 w-12 text-sky-600 mx-auto" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
            <p className="mt-4 text-gray-600">Loading workspace dashboard...</p>
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1 max-w-7xl mx-auto w-full px-6 md:px-12 lg:px-16 py-10">
        <div className="mb-8">
          <h1 className="text-3xl md:text-4xl font-extrabold tracking-tight text-gray-900">
            Workspace Owner Dashboard
          </h1>
          <p className="text-gray-600 mt-2">Manage your workspaces, bookings, and tour requests</p>
        </div>

        <section className="mb-10">
          <div className="flex items-center justify-between mb-6">
            <div>
              <p className="text-sm font-semibold uppercase tracking-wide text-sky-600">Owner Capabilities</p>
              <h2 className="text-2xl font-bold text-gray-900 mt-1">Everything you can run from this workspace</h2>
            </div>
            <span className="text-sm text-gray-500">
              {OWNER_CAPABILITIES.length} owner workflows
            </span>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
            {OWNER_CAPABILITIES.map((capability) => (
              <div
                key={capability.key}
                className="p-6 rounded-2xl border border-gray-100 bg-white shadow-sm hover:shadow-md transition-shadow"
              >
                <div className="text-3xl mb-4">{capability.icon}</div>
                <h3 className="text-lg font-semibold text-gray-900">{capability.title}</h3>
                <p className="text-sm text-gray-600 mt-2">{capability.description}</p>
                <div className="mt-4">
                  {capability.actionType === 'tab' && (
                    <button
                      type="button"
                      onClick={() => handleCapabilitySelect(capability)}
                      className="inline-flex items-center text-sm font-medium text-sky-600 hover:text-sky-700"
                    >
                      {capability.actionLabel}
                      <span className="ml-2">→</span>
                    </button>
                  )}
                  {capability.actionType === 'link' && (
                    <Link
                      to={capability.href}
                      className="inline-flex items-center text-sm font-medium text-sky-600 hover:text-sky-700"
                    >
                      {capability.actionLabel}
                      <span className="ml-2">→</span>
                    </Link>
                  )}
                  {capability.actionType === 'info' && (
                    <span className="inline-flex items-center px-3 py-1 text-xs font-semibold text-slate-700 bg-slate-100 rounded-full">
                      {capability.badge || 'Insight'}
                    </span>
                  )}
                </div>
              </div>
            ))}
          </div>
        </section>

        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg text-red-700">
            {error}
          </div>
        )}

        {/* Stats Tab */}
        {activeTab === 'stats' && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
            <div className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-gradient-to-br from-blue-50 to-indigo-50">
              <div className="text-sm text-gray-600 mb-1">Total Spaces</div>
              <div className="text-3xl font-bold text-gray-900">{stats.totalSpaces}</div>
            </div>
            <div className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-gradient-to-br from-emerald-50 to-green-50">
              <div className="text-sm text-gray-600 mb-1">Total Bookings</div>
              <div className="text-3xl font-bold text-gray-900">{stats.totalBookings}</div>
              <div className="text-xs text-gray-500 mt-2">Active: {stats.activeBookings}</div>
            </div>
            <div className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-gradient-to-br from-amber-50 to-orange-50">
              <div className="text-sm text-gray-600 mb-1">Total Revenue</div>
              <div className="text-3xl font-bold text-gray-900">₹{stats.totalRevenue?.toLocaleString() || 0}</div>
            </div>
            <div className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-gradient-to-br from-purple-50 to-pink-50">
              <div className="text-sm text-gray-600 mb-1">Tour Requests</div>
              <div className="text-3xl font-bold text-gray-900">{tourBookings.length}</div>
            </div>
          </div>
        )}

        {/* Tabs */}
        <div id="owner-tabs" className="mb-6 border-b border-gray-200">
          <nav className="-mb-px flex space-x-8">
            {['stats', 'spaces', 'bookings', 'tours'].map((tab) => (
              <button
                key={tab}
                onClick={() => setActiveTab(tab)}
                className={`py-4 px-1 border-b-2 font-medium text-sm capitalize ${
                  activeTab === tab
                    ? 'border-sky-500 text-sky-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                {tab === 'tours' ? 'Tour Requests' : tab}
              </button>
            ))}
          </nav>
        </div>

        {/* Spaces Tab */}
        {activeTab === 'spaces' && (
          <div className="space-y-4">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-xl font-bold text-gray-900">My Workspaces</h2>
              <Link
                to="/spaces/new"
                className="px-4 py-2 bg-sky-600 text-white rounded-lg hover:bg-sky-700 transition"
              >
                + Add New Space
              </Link>
            </div>
            {spaces.length === 0 ? (
              <div className="text-center py-12 bg-gray-50 rounded-lg">
                <p className="text-gray-600 mb-4">No spaces found</p>
                <Link
                  to="/spaces/new"
                  className="inline-block px-6 py-2 bg-sky-600 text-white rounded-lg hover:bg-sky-700 transition"
                >
                  Create Your First Space
                </Link>
              </div>
            ) : (
              spaces.map((space) => (
                <div key={space._id} className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-white">
                  <div className="flex items-start justify-between">
                    <div className="flex-1">
                      <h3 className="text-lg font-bold text-gray-900">{space.name}</h3>
                      <p className="text-sm text-gray-600 mt-1">{space.city} • {space.type}</p>
                      <p className="text-sm font-semibold text-gray-900 mt-2">₹{space.pricePerDay}/day</p>
                      {space.rating && (
                        <div className="mt-2">
                          <span className="text-sm text-gray-600">Rating: </span>
                          <span className="text-sm font-semibold text-amber-600">{space.rating} ⭐</span>
                        </div>
                      )}
                    </div>
                    <button
                      onClick={() => handleDeleteSpace(space._id)}
                      className="ml-4 px-4 py-2 text-sm text-red-600 hover:text-red-900 border border-red-200 rounded-lg hover:bg-red-50"
                    >
                      Delete
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        )}

        {/* Bookings Tab */}
        {activeTab === 'bookings' && (
          <div className="space-y-4">
            {bookings.length === 0 ? (
              <div className="text-center py-12 bg-gray-50 rounded-lg">
                <p className="text-gray-600">No bookings found</p>
              </div>
            ) : (
              bookings.map((booking) => (
                <div key={booking._id} className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-white">
                  <div className="flex items-start justify-between">
                    <div className="flex-1">
                      <h3 className="text-lg font-bold text-gray-900">{booking.space?.name || 'Space'}</h3>
                      <p className="text-sm text-gray-600 mt-1">
                        User: {booking.user?.fullName || booking.user?.email} • {new Date(booking.bookingDate).toLocaleDateString()}
                      </p>
                      <p className="text-sm font-semibold text-gray-900 mt-2">₹{booking.totalAmount}</p>
                      <span className={`inline-block mt-2 px-2 py-1 rounded text-xs font-semibold ${
                        booking.status === 'confirmed' ? 'bg-emerald-100 text-emerald-700' :
                        booking.status === 'pending' ? 'bg-amber-100 text-amber-700' :
                        'bg-gray-100 text-gray-700'
                      }`}>
                        {booking.status}
                      </span>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        )}

        {/* Tour Bookings Tab */}
        {activeTab === 'tours' && (
          <div className="space-y-4">
            {tourBookings.length === 0 ? (
              <div className="text-center py-12 bg-gray-50 rounded-lg">
                <p className="text-gray-600">No tour requests found</p>
              </div>
            ) : (
              tourBookings.map((tour) => (
                <div key={tour._id} className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-white">
                  <div className="flex items-start justify-between">
                    <div className="flex-1">
                      <h3 className="text-lg font-bold text-gray-900">{tour.space?.name || 'Space'}</h3>
                      <p className="text-sm text-gray-600 mt-1">
                        {tour.contactName} ({tour.contactEmail}) • {new Date(tour.tourDate).toLocaleDateString()} at {tour.tourTime}
                      </p>
                      <span className={`inline-block mt-2 px-2 py-1 rounded text-xs font-semibold ${
                        tour.status === 'confirmed' ? 'bg-emerald-100 text-emerald-700' :
                        tour.status === 'pending' ? 'bg-amber-100 text-amber-700' :
                        'bg-gray-100 text-gray-700'
                      }`}>
                        {tour.status}
                      </span>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        )}
      </main>
      <Footer />
    </div>
  );
}
